const ASCII_CHARS = "@#S%?*+;:,. ";
const mapScale = (ASCII_CHARS.length - 1) / 255;

self.onmessage = (e) => {
    const { data, width, isColor} = e.data;

    let result = [];
    const len = data.length;


    for (let i = 0; i < len; i += 4) {
      const r = data[i];
      const g = data[i + 1];
      const b = data[i + 2];

      const brightness = (r + g + b) / 3;
      const char = ASCII_CHARS[brightness * mapScale];

      if (isColor) {
        result.push(
        `<span style="color: rgb ${r}, ${g}, ${b}">${char}</span>`
        );
      } else {
        result.push(char);
      }

      if ((i / 4 + 1) % width === 0) {
        result.push(isColor ? "<br/>" : "\n");
      }
    }
    self.postMessage(result.join(""));
}
